@app.before_request
def _gen_nonce():
    g.csp_nonce = secrets.token_urlsafe(16)

@app.after_request
def set_security_headers(response):
    # ── CORS — whitelist exata (sem substring match) ──
    origin = request.headers.get('Origin', '')
    if origin in _ALLOWED_ORIGINS:
        response.headers['Access-Control-Allow-Origin']  = origin
        response.headers['Access-Control-Allow-Methods'] = 'GET, POST, OPTIONS'
        response.headers['Access-Control-Allow-Headers'] = 'Content-Type'

    # ── Segurança ──
    nonce = getattr(g, 'csp_nonce', '')
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Cross-Origin-Opener-Policy'] = 'same-origin'
    response.headers['Cross-Origin-Resource-Policy'] = 'same-origin'
    # CSP restritivo — sem 'unsafe-inline' em script-src (todo JS é externo)
    # GA carrega via tag injetada; permitido por host. Inline GA bootstrap usa nonce.
    # NOTA: 'unsafe-inline' necessário porque o HTML usa ~36 handlers inline (onclick=...).
    # Nonce não pode coexistir com 'unsafe-inline' (CSP Level 2+ ignora o segundo), e
    # atributos de evento HTML nunca recebem nonce. Refatoração futura: mover listeners
    # para main.js com addEventListener. Por ora mantém 'unsafe-inline' (proteção XSS
    # reduzida mas site funcional; demais diretivas continuam restritivas).
    response.headers['Content-Security-Policy'] = (
        "default-src 'self'; "
        "script-src 'self' 'unsafe-inline' https://www.googletagmanager.com https://pagead2.googlesyndication.com; "
        "style-src 'self' 'unsafe-inline' https://fonts.googleapis.com; "
        "font-src 'self' https://fonts.gstatic.com; "
        "img-src 'self' data: https://www.googletagmanager.com https://www.google-analytics.com; "
        "connect-src 'self' https://www.google-analytics.com https://analytics.google.com https://stats.g.doubleclick.net; "
        "manifest-src 'self'; "
        "worker-src 'self'; "
        "frame-ancestors 'none'; "
        "object-src 'none'; "
        "base-uri 'self'; "
        "form-action 'self'; "
        "upgrade-insecure-requests;"
    )
    response.headers['Referrer-Policy'] = 'strict-origin-when-cross-origin'
    response.headers['Permissions-Policy'] = 'geolocation=(), microphone=(), camera=(), usb=(), payment=(), interest-cohort=()'
    if os.environ.get('ENV','').lower() == 'production' or os.environ.get('FLASK_ENV') == 'production':
        response.headers['Strict-Transport-Security'] = 'max-age=63072000; includeSubDomains; preload'
    response.headers.pop('Server', None)
    response.headers['X-Powered-By'] = 'PokerCalc'

    # ── Cache-Control por tipo de conteúdo ──
    path = request.path
    if path.startswith('/static/'):
        # Assets com hash/versão estável: cache agressivo de 1 ano + immutable
        if path.endswith(('.min.js', '.min.css')) or '/fonts/' in path:
            response.headers['Cache-Control'] = 'public, max-age=31536000, immutable'
        elif path.endswith('.json'):
            # content.json: revalidável, 1h
            response.headers['Cache-Control'] = 'public, max-age=3600'
        else:
            # demais estáticos (.js/.css não-minificado, imagens): 1 dia
            response.headers['Cache-Control'] = 'public, max-age=86400'
    elif path in ('/favicon.svg', '/favicon.ico', '/favicon.png', '/apple-touch-icon.png', '/apple-touch-icon-precomposed.png'):
        # favicon: cache por 7 dias
        response.headers['Cache-Control'] = 'public, max-age=604800, immutable'
    elif path == '/healthcheck':
        # healthcheck: sem cache
        response.headers['Cache-Control'] = 'no-store'
    elif request.method == 'GET' and path == '/':
        # HTML principal: revalidar sempre (conteúdo pode mudar com deploy)
        response.headers['Cache-Control'] = 'public, max-age=300, must-revalidate'
    elif request.method in ('POST',):
        # APIs de cálculo: sem cache
        response.headers['Cache-Control'] = 'no-store'

    # (Bloco de compressão Gzip manual removido: Flask-Compress já cuida
    # de Brotli + gzip com negociação correta de Accept-Encoding.)

    return response

