def _patch_fonts():
    global HTML, _ERROR_PAGE
    FONT_DEF = [
        ('Rajdhani',       '400', 'rajdhani-400.woff2'),
        ('Rajdhani',       '500', 'rajdhani-500.woff2'),
        ('Rajdhani',       '600', 'rajdhani-600.woff2'),
        ('Rajdhani',       '700', 'rajdhani-700.woff2'),
        ('JetBrains Mono', '400', 'jetbrainsmono-400.woff2'),
        ('JetBrains Mono', '500', 'jetbrainsmono-500.woff2'),
        ('JetBrains Mono', '700', 'jetbrainsmono-700.woff2'),
    ]
    font_dir = os.path.join(_APP_DIR, 'static', 'fonts')
    for family, weight, fname in FONT_DEF:
        if not os.path.exists(os.path.join(font_dir, fname)):
            return  # alguma fonte faltando → mantém Google Fonts
    local_style = '<link rel="stylesheet" href="/static/css/fonts.css"/>'
    HTML = HTML.replace(
        '<link href="https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;500;600;700'
        '&family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet"/>',
        local_style
    )
    _ERROR_PAGE = _ERROR_PAGE.replace(
        '<link href="https://fonts.googleapis.com/css2?family=Rajdhani:wght@400;600;700'
        '&family=JetBrains+Mono:wght@700&display=swap" rel="stylesheet"/>',
        local_style
    )
    print('  🔤  Fontes auto-hospedadas (static/fonts/) — sem Google Fonts.')

_patch_fonts()

# ── Produção: usar versões minificadas dos assets ──
def _patch_minified_assets():
    global HTML, _ERROR_PAGE
    if os.environ.get('ENV','').lower() != 'production':
        print('  🛠  ENV != production — usando assets não minificados')
        return
    asset_map = {
        '/static/js/main.js':    '/static/js/main.min.js',
        '/static/js/pwa.js':     '/static/js/pwa.min.js',
        '/static/css/main.css':  '/static/css/main.min.css',
        '/static/css/pages.css': '/static/css/pages.min.css',
        '/static/css/fonts.css': '/static/css/fonts.min.css',
    }
    swapped = 0
    for orig, mini in asset_map.items():
        mini_path = os.path.join(_APP_DIR, mini.lstrip('/'))
        if not os.path.exists(mini_path):
            continue
        if orig in HTML:
            HTML = HTML.replace(orig, mini)
            swapped += 1
        if orig in _ERROR_PAGE:
            _ERROR_PAGE = _ERROR_PAGE.replace(orig, mini)
            swapped += 1
    print(f'  🚀  Produção: {swapped} referências de asset trocadas para .min')

_patch_minified_assets()

